diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..1b26919ae406 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1850,6 +1850,40 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }

+  // Handle (fcmp olt/ole X, C0) &| (fcmp olt/ole X, C1) and
+  //        (fcmp ogt/oge X, C0) &| (fcmp ogt/oge X, C1)
+  // where C0 and C1 are constants.
+  if (LHS0 == RHS0) {
+    const APFloat *C0, *C1;
+    if (match(LHS1, m_APFloat(C0)) && match(RHS1, m_APFloat(C1))) {
+      // For ordered less-than comparisons:
+      // or (fcmp olt/ole X, C0), (fcmp olt/ole X, C1) -> fcmp olt/ole X, max(C0, C1)
+      // and (fcmp olt/ole X, C0), (fcmp olt/ole X, C1) -> fcmp olt/ole X, min(C0, C1)
+      // For ordered greater-than comparisons:
+      // or (fcmp ogt/oge X, C0), (fcmp ogt/oge X, C1) -> fcmp ogt/oge X, min(C0, C1)
+      // and (fcmp ogt/oge X, C0), (fcmp ogt/oge X, C1) -> fcmp ogt/oge X, max(C0, C1)
+      if (PredL == PredR) {
+        APFloat::cmpResult CmpResult = C0->compare(*C1);
+        if (CmpResult == APFloat::cmpEqual)
+          return LHS;
+        if (PredL == FCmpInst::FCMP_OLT || PredL == FCmpInst::FCMP_OLE) {
+          // For less-than: larger constant means larger range
+          if (IsAnd)
+            return CmpResult == APFloat::cmpLessThan ? LHS : RHS;
+          else
+            return CmpResult == APFloat::cmpLessThan ? RHS : LHS;
+        }
+        if (PredL == FCmpInst::FCMP_OGT || PredL == FCmpInst::FCMP_OGE) {
+          // For greater-than: smaller constant means larger range
+          if (IsAnd)
+            return CmpResult == APFloat::cmpGreaterThan ? LHS : RHS;
+          else
+            return CmpResult == APFloat::cmpGreaterThan ? RHS : LHS;
+        }
+      }
+    }
+  }
+
   return nullptr;
 }

